SELECT investigation_id
FROM investigations
WHERE outcome = 'not sustained';

SELECT name
FROM complainants
WHERE complainant_id IN (SELECT DISTINCT complainant_id FROM complaints);

SELECT retention_period
FROM retention_policy
WHERE outcome = 'not sustained';

SELECT name
FROM investigators
ORDER BY name ASC;

SELECT name, phone_number
FROM complainants
WHERE complainant_id = 0;
